<script lang="ts">
  import { onMount } from 'svelte';
  import { page } from '$app/state';
  import { resolve } from '$app/paths';
  import type { AvCatalogItem, Capture } from '@zztt/aby-domain';

  type TileSize = 'small'|'medium'|'large';
  type Sort = 'title'|'year'|'recent';
  type AudioTrack = {index:number;codec?:string;language?:string;title?:string;channels?:number};
  type SubtitleTrack = {index:number;codec?:string;language?:string;title?:string;forced?:boolean;hearingImpaired?:boolean};
  let items = $state<AvCatalogItem[]>([]); let selected = $state<AvCatalogItem|null>(null); let video = $state<HTMLVideoElement|null>(null); let videoUrl=$state('');
  let loading=$state(true); let message=$state(''); let search=$state(''); let kind=$state('all'); let decade=$state('all'); let country=$state('all'); let sort=$state<Sort>('title');
  let settingsOpen=$state(false); let tileSize=$state<TileSize>('medium'); let showTitle=$state(true); let showYear=$state(true); let showDirector=$state(true); let showKind=$state(false); let showCountry=$state(false); let showLanguages=$state(false); let showState=$state(false);
  let speed=$state(1); let audioTracks=$state<AudioTrack[]>([]); let selectedAudio=$state<number|null>(null); let subtitleTracks=$state<SubtitleTrack[]>([]); let subtitlesOn=$state(true); let doubleSubtitles=$state(false); let primarySubtitle=$state<number|null>(null); let secondarySubtitle=$state<number|null>(null); let subtitleSize=$state(100);
  let captureIn=$state<number|null>(null); let captureOut=$state<number|null>(null); let captureLabel=$state(''); let lastCapture=$state<Capture|null>(null);
  let libraryWidth=$state(44); let priorLibraryWidth=$state(44);

  const decades = $derived([...new Set(items.map((item)=>item.year?`${Math.floor(item.year/10)*10}s`:null).filter(Boolean) as string[])].sort());
  const countries = $derived([...new Set(items.flatMap((item)=>item.countries?.length?item.countries:(item.country??'').split(',').map((value)=>value.trim()).filter(Boolean)))].sort());
  const filtered = $derived.by(() => items.filter((item) => {
    const itemCountries=item.countries?.length?item.countries:(item.country??'').split(',').map((value)=>value.trim()).filter(Boolean);
    const haystack=[item.title,item.originalTitle,item.director,item.composer,item.entity,item.saga,...itemCountries,...item.languages,...item.tags].filter(Boolean).join(' ').toLocaleLowerCase();
    if(search.trim()&&!haystack.includes(search.trim().toLocaleLowerCase())) return false;
    if(kind!=='all'&&item.kind!==kind) return false;
    if(decade!=='all'&&(!item.year||`${Math.floor(item.year/10)*10}s`!==decade)) return false;
    if(country!=='all'&&!itemCountries.includes(country)) return false;
    return true;
  }).sort((left,right)=>sort==='year'?(left.year??9999)-(right.year??9999):sort==='recent'?right.createdAt.localeCompare(left.createdAt):left.title.localeCompare(right.title)));

  onMount(async()=>{
    try {
      const response=await fetch('/api/av/items'); const body=await response.json(); if(!response.ok) throw new Error(body.error?.message??'VIEW could not load the AV catalog'); items=body.items??[];
      restoreSettings(); const requested=page.url.searchParams.get('item'); const item=items.find((candidate)=>candidate.id===requested); if(item) await selectItem(item);
    } catch(error){message=error instanceof Error?error.message:'VIEW could not be loaded';} finally{loading=false;}
  });

  function restoreSettings(){const stored=localStorage.getItem('aby.view-gallery-settings');if(!stored)return;try{const value=JSON.parse(stored);tileSize=['small','medium','large'].includes(value.tileSize)?value.tileSize:'medium';showTitle=value.showTitle!==false;showYear=value.showYear!==false;showDirector=value.showDirector!==false;showKind=value.showKind===true;showCountry=value.showCountry===true;showLanguages=value.showLanguages===true;showState=value.showState===true;}catch{/* defaults remain */}}
  function persist(){localStorage.setItem('aby.view-gallery-settings',JSON.stringify({tileSize,showTitle,showYear,showDirector,showKind,showCountry,showLanguages,showState}));}
  function formatTime(ms:number){const seconds=Math.max(0,Math.floor(ms/1000));return `${Math.floor(seconds/60)}:${String(seconds%60).padStart(2,'0')}`;}
  async function selectItem(item:AvCatalogItem){selected=item;captureIn=null;captureOut=null;lastCapture=null;audioTracks=[];subtitleTracks=[];selectedAudio=null;primarySubtitle=null;secondarySubtitle=null;const response=await fetch(`/api/av/items/${item.id}/playback`);const body=await response.json();if(!response.ok){message=body.error?.message??'Playback unavailable';return;}videoUrl=body.url;audioTracks=body.audioTracks??[];subtitleTracks=body.subtitleTracks??[];selectedAudio=audioTracks[0]?.index??null;primarySubtitle=subtitleTracks[0]?.index??null;message='';}
  function closePlayer(){selected=null;videoUrl='';captureIn=null;captureOut=null;lastCapture=null;audioTracks=[];subtitleTracks=[];}
  function updateSpeed(){if(video)video.playbackRate=speed;}
  function updateAudio(){const nativeTracks=(video as (HTMLVideoElement&{audioTracks?:ArrayLike<{enabled:boolean}>})|null)?.audioTracks;if(!nativeTracks||selectedAudio===null){message=audioTracks.length>1?'This browser exposes the tracks but cannot switch audio in this container.':' ';return;}audioTracks.forEach((track,position)=>{const native=nativeTracks[position];if(native)native.enabled=track.index===selectedAudio;});message='';}
  function subtitleLabel(track:SubtitleTrack){return [track.language??'und',track.title,track.forced?'forced':'',track.hearingImpaired?'SDH':''].filter(Boolean).join(' · ');}
  function togglePlayerFocus(){if(libraryWidth===0) libraryWidth=priorLibraryWidth; else {priorLibraryWidth=libraryWidth;libraryWidth=0;}}
  function startResize(event:PointerEvent){if(libraryWidth===0)return;const move=(next:PointerEvent)=>libraryWidth=Math.min(68,Math.max(18,next.clientX/window.innerWidth*100));const stop=()=>{window.removeEventListener('pointermove',move);window.removeEventListener('pointerup',stop);};window.addEventListener('pointermove',move);window.addEventListener('pointerup',stop);event.preventDefault();}
  function setCapturePoint(kind:'in'|'out'){const value=Math.round((video?.currentTime??0)*1000);if(kind==='in')captureIn=value;else captureOut=value;}
  async function saveCapture(){if(!selected||captureIn===null||captureOut===null||captureOut<=captureIn){message='Set an IN and an OUT after it.';return;}const response=await fetch('/api/captures',{method:'POST',headers:{'content-type':'application/json'},body:JSON.stringify({mediaKind:'video',avItemId:selected.id,startTimeMs:captureIn,endTimeMs:captureOut,...(captureLabel.trim()?{label:captureLabel.trim()}:{}),annotations:[]})});const body=await response.json();if(!response.ok){message=body.error?.message??'Capture could not be saved';return;}lastCapture=body.capture;message='Capture saved to WORKSPACE.';}
  async function copyCaptureUrl(){if(!lastCapture)return;const url=new URL(resolve('/share/[token]',{token:lastCapture.shareToken}),window.location.origin).href;await navigator.clipboard.writeText(url);message='Closed capture URL copied.';}
</script>

<!-- eslint-disable svelte/no-navigation-without-resolve -->

<svelte:head><title>VIEW · Aby</title><meta name="description" content="Audiovisual mosaic and temporal player." /></svelte:head>

<main class="view" class:playing={Boolean(selected)} class:focus={libraryWidth===0} style={`width:100%;max-width:none;margin:0;padding:0;--library-width:${libraryWidth}vw`}>
  <section class="library">
    <header class="view-toolbar"><div><span>VIEW</span><strong>{filtered.length} / {items.length} FILMS</strong></div><input type="search" bind:value={search} placeholder="SEARCH TITLE · DIRECTOR · COUNTRY · LANGUAGE" aria-label="Search AV catalog" /><select bind:value={kind} aria-label="Kind filter"><option value="all">ALL TYPES</option><option value="film">FILM</option><option value="episode">EPISODE</option><option value="video">VIDEO</option><option value="archive">ARCHIVE</option><option value="personal">PERSONAL</option></select><select bind:value={decade} aria-label="Decade filter"><option value="all">ALL DECADES</option>{#each decades as value (value)}<option value={value}>{value}</option>{/each}</select><select bind:value={country} aria-label="Country filter"><option value="all">ALL COUNTRIES</option>{#each countries as value (value)}<option value={value}>{value}</option>{/each}</select><select bind:value={sort} aria-label="Sort catalog"><option value="title">TITLE</option><option value="year">YEAR</option><option value="recent">RECENT</option></select><button class:active={settingsOpen} onclick={()=>settingsOpen=!settingsOpen} aria-label="Display properties">DISPLAY</button></header>
    {#if settingsOpen}<aside class="display-panel"><header><span>PROPERTIES</span><button onclick={()=>settingsOpen=false}>×</button></header><label><input type="checkbox" bind:checked={showTitle} onchange={persist}/> TITLE</label><label><input type="checkbox" bind:checked={showYear} onchange={persist}/> YEAR</label><label><input type="checkbox" bind:checked={showDirector} onchange={persist}/> DIRECTOR</label><label><input type="checkbox" bind:checked={showKind} onchange={persist}/> TYPE</label><label><input type="checkbox" bind:checked={showCountry} onchange={persist}/> COUNTRY</label><label><input type="checkbox" bind:checked={showLanguages} onchange={persist}/> LANGUAGES</label><label><input type="checkbox" bind:checked={showState} onchange={persist}/> STORAGE STATE</label><h2>SIZE</h2><div>{#each ['small','medium','large'] as size (size)}<button class:active={tileSize===size} onclick={()=>{tileSize=size as TileSize;persist();}}>{size.slice(0,1).toUpperCase()}</button>{/each}</div></aside>{/if}
    {#if loading}<p class="state">…</p>{:else if items.length===0}<div class="empty"><h1>No films committed yet.</h1><p>Source selection and metadata editing now live in INSPECT.</p><a href={resolve('/inspect') + '?media=av'}>OPEN INSPECT · AV</a></div>{:else if filtered.length===0}<p class="state">No films match the current filters.</p>{:else}<div class="mosaic" class:small={tileSize==='small'} class:large={tileSize==='large'}>{#each filtered as item (item.id)}<button class="film" class:active={selected?.id===item.id} onclick={()=>selectItem(item)}><span class="cover">{#if item.posterUrl}<img src={item.posterUrl} alt=""/>{:else}<i>{item.title.slice(0,1)}</i>{/if}<em>{item.kind}</em></span>{#if showTitle||showYear||showDirector||showKind||showCountry||showLanguages||showState}<span class="meta">{#if showTitle}<strong>{item.title}</strong>{/if}{#if showDirector}<small>{item.director??item.treeValue}</small>{/if}{#if showYear}<small>{item.year??'—'}</small>{/if}{#if showKind}<small>{item.kind}</small>{/if}{#if showCountry}<small>{(item.countries?.length?item.countries:[item.country]).filter(Boolean).join(' · ')||'—'}</small>{/if}{#if showLanguages}<small>{item.languages.join(' · ')||'—'}</small>{/if}{#if showState}<small>{item.state}</small>{/if}</span>{/if}</button>{/each}</div>{/if}
  </section>

  {#if selected}<div class="divider" role="separator" aria-orientation="vertical" aria-label="Resize mosaic and player" onpointerdown={startResize}></div><section class="player-panel">
    <header><button onclick={closePlayer}>← MOSAIC</button><div><span>{selected.year??'—'} · {selected.kind} · {selected.state}</span><strong>{selected.title}</strong><small>{selected.director??selected.treeValue}</small></div><button onclick={togglePlayerFocus}>{libraryWidth===0?'SHOW MOSAIC':'PLAYER FOCUS'}</button><a href={resolve('/inspect') + '?media=av'}>INSPECT AV ↗</a></header>
    <div class="screen" style={`--subtitle-size:${subtitleSize}%`}><!-- svelte-ignore a11y_media_has_caption --><video bind:this={video} src={videoUrl} poster={selected.posterUrl} controls playsinline onloadedmetadata={updateAudio} onratechange={()=>speed=video?.playbackRate??1}>{#if subtitlesOn&&primarySubtitle!==null}<track kind="subtitles" src={`/api/av/items/${selected.id}/subtitles/${primarySubtitle}`} srclang={subtitleTracks.find((track)=>track.index===primarySubtitle)?.language??'und'} label={subtitleLabel(subtitleTracks.find((track)=>track.index===primarySubtitle)!)} default />{/if}{#if subtitlesOn&&doubleSubtitles&&secondarySubtitle!==null&&secondarySubtitle!==primarySubtitle}<track kind="subtitles" src={`/api/av/items/${selected.id}/subtitles/${secondarySubtitle}`} srclang={subtitleTracks.find((track)=>track.index===secondarySubtitle)?.language??'und'} label={subtitleLabel(subtitleTracks.find((track)=>track.index===secondarySubtitle)!)} default />{/if}</video></div>
    <div class="film-info">{#if selected.originalTitle}<p><span>ORIGINAL</span>{selected.originalTitle}</p>{/if}{#if selected.summary}<p class="summary">{selected.summary}</p>{/if}<dl><div><dt>COUNTRIES</dt><dd>{(selected.countries?.length?selected.countries:[selected.country]).filter(Boolean).join(' · ')||'—'}</dd></div><div><dt>LANGUAGES</dt><dd>{selected.languages.join(' · ')||'—'}</dd></div><div><dt>COMPOSER</dt><dd>{selected.composer??'—'}</dd></div><div><dt>TAGS</dt><dd>{selected.tags.join(' · ')||'—'}</dd></div><div><dt>IMDb</dt><dd>{selected.externalIds.imdb??'—'}</dd></div><div><dt>TMDB</dt><dd>{selected.externalIds.tmdb??'—'}</dd></div></dl>{#if selected.credits.length}<details><summary>CREDITS · {selected.credits.length}</summary><div class="credits">{#each selected.credits as credit (`${credit.role}:${credit.name}:${credit.character??''}`)}<p><strong>{credit.name}</strong><span>{credit.role}{credit.character?` · ${credit.character}`:''}</span></p>{/each}</div></details>{/if}</div>
    <aside class="controls"><div><strong>AUDIO</strong><select bind:value={selectedAudio} onchange={updateAudio} disabled={!audioTracks.length}>{#if !audioTracks.length}<option value={null}>NO TRACK DATA</option>{/if}{#each audioTracks as track (track.index)}<option value={track.index}>{track.language??'und'} · {track.title??track.codec??`track ${track.index}`}{track.channels?` · ${track.channels}ch`:''}</option>{/each}</select></div><div><strong>SUBTITLES</strong><button class:active={subtitlesOn} onclick={()=>subtitlesOn=!subtitlesOn}>{subtitlesOn?'ON':'OFF'}</button><select bind:value={primarySubtitle} disabled={!subtitleTracks.length}><option value={null}>NO TRACK</option>{#each subtitleTracks as track (track.index)}<option value={track.index}>{subtitleLabel(track)}</option>{/each}</select><button onclick={()=>message='Configure OpenSubtitles from INSPECT · AV → Subtitle providers.'}>FIND OTHER</button></div><div><strong>DOUBLE</strong><button class:active={doubleSubtitles} onclick={()=>doubleSubtitles=!doubleSubtitles}>{doubleSubtitles?'ON':'OFF'}</button><select bind:value={secondarySubtitle} disabled={!doubleSubtitles||!subtitleTracks.length}><option value={null}>NO SECOND TRACK</option>{#each subtitleTracks as track (track.index)}<option value={track.index}>{subtitleLabel(track)}</option>{/each}</select><label>SIZE <input bind:value={subtitleSize} type="range" min="70" max="180"/></label></div><div><strong>SPEED</strong><select bind:value={speed} onchange={updateSpeed}>{#each [.25,.5,.75,1,1.25,1.5,2] as value (value)}<option value={value}>{value}×</option>{/each}</select></div><div class="capture"><strong>CAPTURE</strong><button onclick={()=>setCapturePoint('in')}>IN {captureIn===null?'—':formatTime(captureIn)}</button><button onclick={()=>setCapturePoint('out')}>OUT {captureOut===null?'—':formatTime(captureOut)}</button><input bind:value={captureLabel} placeholder="Annotation / label"/><button class="signal" onclick={saveCapture}>SAVE + SHARE</button>{#if lastCapture}<a href={resolve('/share/[token]',{token:lastCapture.shareToken})} target="_blank">OPEN URL ↗</a><button onclick={copyCaptureUrl}>COPY URL</button>{/if}</div></aside>
  </section>{/if}
  {#if message}<div class="message">{message}</div>{/if}
</main>

<style>
  .view{min-height:calc(100svh - 64px);background:#090a09}.library{position:relative;min-height:calc(100svh - 64px)}.view.playing{display:grid;grid-template-columns:minmax(360px,44vw) minmax(0,1fr)}.playing .library{height:calc(100svh - 64px);overflow:hidden;border-right:1px solid var(--line)}.view-toolbar{position:sticky;z-index:8;top:64px;min-height:58px;padding:8px 12px;display:grid;grid-template-columns:auto minmax(160px,1fr) repeat(5,auto);gap:6px;align-items:center;border-bottom:1px solid var(--line);background:#0d0e0df2;backdrop-filter:blur(16px)}.view-toolbar>div{display:grid;gap:3px;margin-right:8px}.view-toolbar span{color:var(--signal);font:9px ui-monospace,monospace;letter-spacing:.12em}.view-toolbar strong{font:9px ui-monospace,monospace}.view-toolbar input,.view-toolbar select,.view-toolbar button{height:34px;min-width:0;padding:0 9px;border:1px solid #2b2e29;background:#151714;color:#dfe2da;font:8px ui-monospace,monospace}.view-toolbar button.active{border-color:var(--signal);color:var(--signal)}.mosaic{height:calc(100svh - 122px);box-sizing:border-box;padding:2px 2px 150px;display:grid;grid-template-columns:repeat(auto-fill,minmax(190px,1fr));align-content:start;gap:2px;overflow:auto}.mosaic.small{grid-template-columns:repeat(auto-fill,minmax(120px,1fr))}.mosaic.large{grid-template-columns:repeat(auto-fill,minmax(290px,1fr))}.film{min-width:0;padding:0;border:0;background:#111210;color:#fff;text-align:left}.film.active{box-shadow:inset 0 0 0 2px var(--signal)}.cover{position:relative;aspect-ratio:2/3;display:grid;place-items:center;overflow:hidden;background:#20231d}.cover img{width:100%;height:100%;object-fit:cover}.cover i{color:var(--signal);font:52px Georgia,serif}.cover em{position:absolute;right:6px;bottom:6px;padding:4px 6px;background:#090a09d9;color:var(--signal);font:7px ui-monospace,monospace;text-transform:uppercase}.meta{min-height:58px;padding:9px;display:grid;align-content:start;gap:3px}.meta strong,.meta small{overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.meta strong{font-size:11px;font-weight:500}.meta small{color:var(--muted);font:8px ui-monospace,monospace}.display-panel{position:fixed;z-index:20;top:122px;right:0;width:280px;box-sizing:border-box;padding:18px 22px 28px;background:#151714f7;border-left:1px solid var(--line);border-bottom:1px solid var(--line);backdrop-filter:blur(18px)}.playing .display-panel{right:56vw}.display-panel header{display:flex;justify-content:space-between;align-items:center}.display-panel header span,.display-panel h2{color:var(--muted);font:9px ui-monospace,monospace;letter-spacing:.12em}.display-panel header button{border:0;background:transparent;color:#fff;font-size:18px}.display-panel label{min-height:36px;display:flex;align-items:center;gap:10px;border-bottom:1px solid var(--line);font:9px ui-monospace,monospace}.display-panel input{accent-color:var(--signal)}.display-panel h2{margin:24px 0 10px}.display-panel>div{display:grid;grid-template-columns:repeat(3,1fr);gap:2px}.display-panel>div button{height:36px;border:0;background:#20231d;color:var(--muted)}.display-panel>div button.active{background:var(--signal);color:#0b0c0b}.player-panel{position:sticky;top:64px;height:calc(100svh - 64px);display:grid;grid-template-rows:auto minmax(240px,1fr) minmax(0,.65fr) auto;overflow:hidden;background:#050605}.player-panel>header{min-height:66px;padding:8px 14px;display:grid;grid-template-columns:auto 1fr auto;gap:14px;align-items:center;border-bottom:1px solid var(--line);background:#10110f}.player-panel>header button,.player-panel>header a{border:0;background:transparent;color:var(--signal);font:8px ui-monospace,monospace}.player-panel>header>div{display:grid;gap:3px}.player-panel>header span,.player-panel>header small{color:var(--muted);font:8px ui-monospace,monospace}.player-panel>header strong{font:16px Georgia,serif}.screen{min-height:0;display:grid;place-items:center;background:#000}.screen video{width:100%;height:100%;object-fit:contain}.film-info{padding:14px 18px;overflow:auto;background:#0d0e0d}.film-info>p{margin:0 0 10px}.film-info>p span{margin-right:8px;color:var(--signal);font:8px ui-monospace,monospace}.film-info .summary{color:#c3c6bf;font-size:11px;line-height:1.55}.film-info dl{margin:10px 0;display:grid;grid-template-columns:repeat(4,1fr);gap:8px}.film-info dt{color:var(--muted);font:7px ui-monospace,monospace}.film-info dd{margin:3px 0;font:9px ui-monospace,monospace}.film-info details summary{color:var(--signal);font:8px ui-monospace,monospace}.credits{max-height:160px;overflow:auto}.credits p{margin:0;padding:6px 0;display:grid;grid-template-columns:1fr 1fr;border-bottom:1px solid var(--line);font:8px ui-monospace,monospace}.credits p span{color:var(--muted)}.controls{display:grid;grid-template-columns:1.3fr 1.3fr .5fr 1.8fr;border-top:1px solid var(--line);background:#0d0e0d}.controls>div{min-height:68px;padding:9px 10px;display:flex;gap:6px;align-items:center;flex-wrap:wrap;border-right:1px solid var(--line)}.controls strong{width:100%;color:var(--muted);font:8px ui-monospace,monospace}.controls button,.controls select,.controls input{height:28px;min-width:0;border:1px solid #343730;background:#171916;color:#dfe2da;font:8px ui-monospace,monospace}.controls button.active,.controls .signal{border-color:var(--signal);color:var(--signal)}.controls label{font:8px ui-monospace,monospace}.capture input{flex:1;padding:0 7px}.capture a{color:var(--signal);font:8px ui-monospace,monospace}.state{padding:24px;color:var(--muted);font:10px ui-monospace,monospace}.empty{min-height:calc(100svh - 122px);display:grid;place-content:center;text-align:center}.empty h1{font:34px Georgia,serif}.empty p{color:var(--muted)}.empty a{color:var(--signal);font:10px ui-monospace,monospace}.message{position:fixed;z-index:30;left:18px;bottom:76px;max-width:min(640px,calc(100vw - 36px));padding:10px 12px;background:#111310f2;border-left:3px solid var(--signal);font:10px ui-monospace,monospace}
  @media(max-width:1100px){.view.playing{grid-template-columns:340px 1fr}.view-toolbar{grid-template-columns:auto 1fr auto}.view-toolbar select:nth-of-type(n+2){display:none}.playing .display-panel{right:calc(100vw - 340px)}.controls{grid-template-columns:1fr 1fr}.film-info dl{grid-template-columns:1fr 1fr}}@media(max-width:760px){.view.playing{display:block}.playing .library{display:none}.player-panel{position:relative;top:0;height:calc(100svh - 64px)}.view-toolbar{top:64px;grid-template-columns:auto 1fr auto}.view-toolbar select{display:none}.mosaic{grid-template-columns:repeat(auto-fill,minmax(140px,1fr))}.display-panel,.playing .display-panel{right:0}.controls{max-height:180px;overflow:auto}}
  .view.playing{grid-template-columns:var(--library-width) 6px minmax(0,1fr)}.library{display:grid;grid-template-rows:minmax(0,1fr) auto;min-width:0}.view-toolbar{order:2;position:sticky;top:auto;bottom:0;border-top:1px solid var(--line);border-bottom:0}.mosaic,.state,.empty{order:1;min-height:0}.mosaic{height:auto;padding-bottom:20px}.divider{grid-column:2;position:relative;z-index:12;cursor:col-resize;background:#151714;border-left:1px solid #30332d;border-right:1px solid #30332d}.divider:hover{background:var(--signal)}.player-panel{grid-column:3}.view.focus{grid-template-columns:0 0 minmax(0,1fr)}.focus .library,.focus .divider{display:none}.player-panel>header{grid-template-columns:auto minmax(0,1fr) auto auto}.film-info{display:grid;grid-template-columns:minmax(0,1.4fr) minmax(240px,.8fr);gap:8px 20px;align-content:start}.film-info .summary{grid-column:1}.film-info dl{grid-column:2;grid-row:1/3;grid-template-columns:1fr 1fr;align-content:start}.film-info details{grid-column:1/-1}.controls{grid-template-columns:.85fr 1.25fr 1.25fr .5fr 1.8fr}.screen video::cue{font-size:var(--subtitle-size);background:#000b;color:#fff}.capture button{padding:0 7px}.capture a{white-space:nowrap}@media(max-width:1100px){.view.playing{grid-template-columns:340px 5px minmax(0,1fr)}.film-info{grid-template-columns:1fr}.film-info dl{grid-column:1;grid-row:auto}.controls{grid-template-columns:1fr 1fr}.player-panel>header{grid-template-columns:auto 1fr auto}.player-panel>header a{display:none}}@media(max-width:760px){.divider{display:none}.player-panel{grid-column:1}.library{display:block}.view-toolbar{position:sticky;top:64px;bottom:auto}.film-info{display:block}}
</style>
